const raw =
  $json?.data ??
  $json?.body ??
  $json?.response ??
  $json?.output ??
  '';

const text = Array.isArray(raw)
  ? raw.map(v => String(v ?? '')).join('\n')
  : String(raw ?? '');

const events = text
  .split('\n\n')
  .map(block => block.trim())
  .filter(Boolean);

let atlasAnswer = '';
let workflowAnswer = '';
let llmText = '';
let parseFailed = false;

for (const block of events) {
  const lines = block.split('\n');
  const dataLine = lines.find(line => line.startsWith('data: '));
  if (!dataLine) continue;

  const jsonStr = dataLine.replace(/^data:\s*/, '').trim();
  if (!jsonStr || jsonStr === '[DONE]') continue;

  let evt;
  try {
    evt = JSON.parse(jsonStr);
  } catch {
    continue;
  }

  if (evt?.event === 'message' && typeof evt?.answer === 'string') {
    llmText += evt.answer;
  }

  if (
    evt?.event === 'node_finished' &&
    evt?.data?.node_type === 'answer' &&
    typeof evt?.data?.outputs?.answer === 'string'
  ) {
    atlasAnswer = evt.data.outputs.answer;
  }

  if (
    evt?.event === 'workflow_finished' &&
    typeof evt?.data?.outputs?.answer === 'string'
  ) {
    workflowAnswer = evt.data.outputs.answer;
  }
}

const finalRaw = workflowAnswer || atlasAnswer || llmText || '';

let parsed;
try {
  parsed = JSON.parse(finalRaw);
} catch (e) {
  parseFailed = true;
  parsed = {
    decision: 'REPROCESSAR_CONTEXTO',
    reason: 'Falha ao converter resposta do Atlas em JSON.',
    corrected_message: '',
    correction_instruction: 'Responder novamente respeitando o estágio atual da conversa, pois a validação falhou no parse.'
  };
}

return [
  {
    json: {
      atlas: {
        raw_answer: finalRaw,
        decision: String(parsed?.decision || ''),
        reason: String(parsed?.reason || ''),
        corrected_message: String(parsed?.corrected_message || ''),
        correction_instruction: String(parsed?.correction_instruction || ''),
        validated: !!parsed?.decision,
        parse_failed: parseFailed
      }
    }
  }
];

const responseText = String($json.message?.clean_answer || '').trim();

const passivePatterns = [
  /fico à disposição/i,
  /qualquer dúvida.*me chama/i,
  /me chama depois/i,
  /quando quiser/i,
  /posso te mandar (um )?(material|resumo|estratégia|analise|análise)/i,
  /vou te mandar (um )?(material|resumo|estratégia|analise|análise)/i,
  /se quiser eu te explico melhor/i,
  /qualquer coisa me avisa/i,
  /depois você vê/i,
  /depois você me fala/i
];

const hasPassivePattern = passivePatterns.some((rx) => rx.test(responseText));

const hasActionSignal =
  /\?\s*$/.test(responseText) ||
  /#STATUS:(QUALIFICANDO|QUALIFICADO|QUALIFICADO_INTERESSADO|QUALIFICADO_PEDIU_VALOR|QUALIFICADO_AGENDAR|AGUARDANDO_ESCOLHA_HORARIO|HORARIO_SELECIONADO|AGUARDANDO_EMAIL|CONFIRMAR_AGENDAMENTO|SOLICITAR_NOVAS_OPCOES|HUMANO)/i.test(responseText);

const blocked = hasPassivePattern && !hasActionSignal;

return [
  {
    json: {
      ...$json,
      final_text_checked: responseText,
      blocked_by_passive_ending: blocked,
      passive_ending_reason: blocked ? 'FINAL_SEM_COMPROMISSO' : ''
    }
  }
];

