const cleanAnswer = String($json.message?.clean_answer || '').trim();
const rawAnswer = String($json.message?.raw_answer || '').trim();

const statusMatch = rawAnswer.match(/#STATUS:([A-Z_]+)/);
const proposedStatus = statusMatch ? statusMatch[1].trim() : '';

const lead = $json.lead || {};
const inputs = $json.inputs || {};
const score = $json.score || {};
const summary = inputs.lead_summary || {};

const identificacao = summary.identificacao || {};
const cenario = summary.cenario || {};
const demanda = summary.demanda || {};
const conversa = summary.conversa || {};

const currentStatus = String(inputs.lead_status || '').trim();
const currentIntent = String(inputs.last_intent || '').trim();
const leadScore = Number(score.lead_score || 0);

const agendaStatuses = [
  'QUALIFICADO_AGENDAR',
  'AGUARDANDO_ESCOLHA_HORARIO',
  'HORARIO_SELECIONADO',
  'AGUARDANDO_EMAIL',
  'CONFIRMAR_AGENDAMENTO',
  'SOLICITAR_NOVAS_OPCOES',
  'REUNIAO_CONFIRMADA',
  'REUNIAO_REAGENDAR'
];

const alreadyInAgenda = agendaStatuses.includes(currentStatus);

const company = String(lead.company_name || identificacao.empresa || '').trim();
const instagram = String(lead.instagram || '').trim();
const gmb = String(lead.google_business_profile || '').trim();
const website = String(lead.website || '').trim();

const identifierCount = [company, instagram, gmb, website].filter(Boolean).length;

// Grupo B = contexto comercial mínimo
const hasObjective = !!String(demanda.objetivo || '').trim();
const hasPain = !!String(demanda.dor_principal || '').trim();
const hasBusinessDefined =
  !!String(identificacao.empresa || '').trim() ||
  !!String(cenario.nicho || '').trim();

const hasChannelDefined = !!String(cenario.canal_venda || '').trim();

const sellsOrNearText = [
  cenario.momento || '',
  cenario.estrutura || '',
  conversa.ultimo_contexto || '',
  cleanAnswer || ''
].join(' ').toLowerCase();

const hasSellsOrNear =
  /vende|já vende|ja vende|atende|clientes|comercial|equipe|time|demanda|opera/.test(sellsOrNearText);

const groupBCount = [
  hasObjective,
  hasPain,
  hasBusinessDefined,
  hasChannelDefined,
  hasSellsOrNear
].filter(Boolean).length;

// Grupo C = aderência mínima
const adherenceText = [
  demanda.objetivo || '',
  demanda.investimento || '',
  demanda.decisor || '',
  conversa.ultimo_contexto || '',
  cleanAnswer || ''
].join(' ').toLowerCase();

const wantsClients = /cliente|clientes|lead|leads|venda|vendas|demanda/.test(adherenceText);
const wantsGrowth = /crescer|escala|escalar|expandir|aumentar/.test(adherenceText);
const acceptsInvestment = !!String(demanda.investimento || '').trim();
const isDecisionMaker = !!String(demanda.decisor || '').trim();
const hasDigitalPresence = identifierCount >= 1;
const isResponsive =
  leadScore >= 40 ||
  !!String(inputs.last_user_message || '').trim();

const groupCCount = [
  wantsClients,
  wantsGrowth,
  acceptsInvestment,
  isDecisionMaker,
  hasDigitalPresence,
  isResponsive
].filter(Boolean).length;

// Vetos
const priceColdVeto = currentIntent === 'PEDIU_VALOR' && leadScore < 50;
const comparingLowContextVeto = currentIntent === 'COMPARANDO' && groupBCount < 2;
const unclearVeto = leadScore < 35 && groupBCount < 2;
const noDecisionMakerVeto = !isDecisionMaker && groupCCount < 2;

const blockedByVeto =
  identifierCount < 1 ||
  priceColdVeto ||
  comparingLowContextVeto ||
  unclearVeto ||
  noDecisionMakerVeto;

const gateEligible =
  identifierCount >= 1 &&
  groupBCount >= 2 &&
  groupCCount >= 2 &&
  !blockedByVeto;

// Situações que devem ser bloqueadas
const tryingToAdvance =
  !alreadyInAgenda &&
  (
    proposedStatus === 'QUALIFICADO_AGENDAR' ||
    proposedStatus === 'AGUARDANDO_ESCOLHA_HORARIO'
  );

const shouldHaveAdvanced =
  !alreadyInAgenda &&
  gateEligible &&
  ['QUALIFICANDO', 'QUALIFICADO', 'QUALIFICADO_INTERESSADO', 'QUALIFICADO_PEDIU_VALOR'].includes(proposedStatus);

const blockedByAdvanceGate =
  (tryingToAdvance && !gateEligible) ||
  shouldHaveAdvanced;

let advanceGateReason = '';

if (tryingToAdvance && !gateEligible) {
  advanceGateReason = 'AVANCO_SEM_BATER_REGUA';
} else if (shouldHaveAdvanced) {
  advanceGateReason = 'LOOP_QUALIFICACAO_COM_REGUA_BATIDA';
}

return [
  {
    json: {
      ...$json,
      atlas: {
        ...($json.atlas || {}),
        advance_rule: {
          checked_clean_answer: cleanAnswer,
          checked_raw_answer: rawAnswer,
          proposed_status_from_answer: proposedStatus,
          advance_gate: gateEligible ? 'ELEGIVEL_REUNIAO' : 'INVESTIGAR_MAIS',
          advance_gate_counts: {
            identifier_count: identifierCount,
            group_b_count: groupBCount,
            group_c_count: groupCCount
          },
          blocked_by_advance_gate: blockedByAdvanceGate,
          advance_gate_reason: advanceGateReason
        }
      }
    }
  }
];

