  /(nome da empresa|qual (é|e) a empresa|sua empresa|nome do negócio|nome do negocio)/i.test(cleanAnswer);

const askedNiche =
  /(qual (é|e) o nicho|qual (é|e) o seu nicho|ramo|segmento|área de atuação|area de atuacao)/i.test(cleanAnswer);

const askedObjective =
  /(qual (é|e) o objetivo|principal objetivo|o que você quer resolver|o que quer alcançar|o que quer gerar)/i.test(cleanAnswer);

