    evt = JSON.parse(jsonStr);
  } catch {
    continue;
  }

  if (evt?.event === 'message' && typeof evt?.answer === 'string') {
    llmText += evt.answer;
  }

  if (
    evt?.event === 'node_finished' &&
    evt?.data?.node_type === 'answer' &&
    typeof evt?.data?.outputs?.answer === 'string'
  ) {
    atlasAnswer = evt.data.outputs.answer;
  }

  if (
    evt?.event === 'workflow_finished' &&
    typeof evt?.data?.outputs?.answer === 'string'
  ) {
    workflowAnswer = evt.data.outputs.answer;
  }
}

const finalRaw = workflowAnswer || atlasAnswer || llmText || '';

let parsed;
try {
  parsed = JSON.parse(finalRaw);
} catch (e) {
  parseFailed = true;
  parsed = {
    decision: 'REPROCESSAR_CONTEXTO',
    reason: 'Falha ao converter resposta do Atlas em JSON.',
    corrected_message: '',
    correction_instruction: 'Responder novamente respeitando o estágio atual da conversa, pois a validação falhou no parse.'
  };
}

return [
  {
    json: {
      atlas: {
        raw_answer: finalRaw,
        decision: String(parsed?.decision || ''),
        reason: String(parsed?.reason || ''),
        corrected_message: String(parsed?.corrected_message || ''),
        correction_instruction: String(parsed?.correction_instruction || ''),
        validated: !!parsed?.decision,
        parse_failed: parseFailed
      }
    }
  }
];

